#include <stdio.h>
#include <stdbool.h>
#include <stdlib.h>

/*
 * IoT Control Flow Implementation in C
 * Suitable for embedded systems (Arduino, ESP8266, STM32)
 * Demonstrates: if-else, switch, for loops, state machines
 */

/* Sensor threshold constants */
#define TEMP_HIGH_THRESHOLD 30.0f
#define TEMP_LOW_THRESHOLD 15.0f
#define TEMP_CRITICAL 35.0f

/* Control mode enumeration */
typedef enum {
 MODE_CENTRALIZED = 0,
 MODE_EDGE,
 MODE_HYBRID
} ControlMode;

/* Actuator action types */
typedef enum {
 ACTION_NONE = 0,
 ACTION_AC_ON,
 ACTION_HEATER_ON,
 ACTION_FAN_ON,
 ACTION_ALERT,
 ACTION_SHUTDOWN
} ActuatorAction;

/* Sensor data structure */
typedef struct {
 float temperature;
 float humidity;
 bool motion_detected;
 unsigned long timestamp;
} SensorData;

/* Function prototypes */
ActuatorAction process_edge_control(float temperature);
ActuatorAction process_cloud_control(SensorData *data);
ActuatorAction hybrid_control(SensorData *data, ControlMode mode);
void execute_action(ActuatorAction action);

/*
 * IF-ELSE Control Flow: Edge processing logic
 * Makes immediate decisions without cloud dependency
 */
ActuatorAction process_edge_control(float temperature) {
 printf(" [EDGE] Evaluating temperature: %.1f\n", temperature);

 // Nested IF-ELSE for threshold-based decisions
 if (temperature >= TEMP_CRITICAL) {
 printf(" [EDGE] CRITICAL: Temperature too high!\n");
 return ACTION_SHUTDOWN;
 }
 else if (temperature >= TEMP_HIGH_THRESHOLD) {
 printf(" [EDGE] High temp detected - activating cooling\n");
 return ACTION_AC_ON;
 }
 else if (temperature <= TEMP_LOW_THRESHOLD) {
 printf(" [EDGE] Low temp detected - activating heating\n");
 return ACTION_HEATER_ON;
 }
 else {
 printf(" [EDGE] Temperature in normal range\n");
 return ACTION_NONE;
 }
}

/*
 * Centralized cloud processing simulation
 */
ActuatorAction process_cloud_control(SensorData *data) {
 printf(" [CLOUD] Processing sensor data...\n");
 printf(" Temp: %.1f, Humidity: %.1f, Motion: %s\n",
 data->temperature, data->humidity,
 data->motion_detected ? "YES" : "NO");

 // Complex cloud analytics (simulated)
 if (data->temperature > TEMP_HIGH_THRESHOLD && data->humidity > 70) {
 return ACTION_AC_ON; // High heat + humidity = AC
 }
 else if (data->motion_detected && data->temperature < 20) {
 return ACTION_HEATER_ON; // Motion in cold = heat
 }

 return ACTION_NONE;
}

/*
 * HYBRID Control Flow: Combines edge and cloud decisions
 * Uses SWITCH statement for control mode selection
 */
ActuatorAction hybrid_control(SensorData *data, ControlMode mode) {
 ActuatorAction action;

 // SWITCH-CASE for control mode selection
 switch (mode) {
 case MODE_EDGE:
 printf("[HYBRID] Mode: EDGE (local processing)\n");
 action = process_edge_control(data->temperature);
 break;

 case MODE_CENTRALIZED:
 printf("[HYBRID] Mode: CENTRALIZED (cloud processing)\n");
 action = process_cloud_control(data);
 break;

 case MODE_HYBRID:
 default:
 printf("[HYBRID] Mode: HYBRID (intelligent routing)\n");
 // Time-critical decision at edge
 if (data->temperature >= TEMP_CRITICAL) {
 printf(" -> CRITICAL: Using EDGE for immediate response\n");
 action = process_edge_control(data->temperature);
 }
 else {
 printf(" -> Non-critical: Using CLOUD for analytics\n");
 action = process_cloud_control(data);
 }
 break;
 }

 return action;
}

/*
 * Execute the determined action
 */
void execute_action(ActuatorAction action) {
 // SWITCH-CASE for actuator commands
 switch (action) {
 case ACTION_AC_ON:
 printf("=> ACTUATOR: Turning ON Air Conditioner\n");
 break;
 case ACTION_HEATER_ON:
 printf("=> ACTUATOR: Turning ON Heater\n");
 break;
 case ACTION_FAN_ON:
 printf("=> ACTUATOR: Turning ON Fan\n");
 break;
 case ACTION_ALERT:
 printf("=> ACTUATOR: Sending ALERT notification\n");
 break;
 case ACTION_SHUTDOWN:
 printf("=> ACTUATOR: EMERGENCY SHUTDOWN initiated\n");
 break;
 case ACTION_NONE:
 default:
 printf("=> ACTUATOR: No action required\n");
 break;
 }
}

/*
 * FOR loop: Simulate continuous sensor monitoring
 * Typical embedded system main loop
 */
void run_monitoring_loop(int iterations) {
 printf("\n=== Starting Continuous Monitoring ===\n");

 // FOR loop for fixed iterations
 for (int i = 1; i <= iterations; i++) {
 printf("\n--- Reading %d ---\n", i);

 // Simulate sensor reading
 SensorData data;
 data.temperature = 20.0f + (float)(rand() % 20); // 20-40 range
 data.humidity = 50.0f + (float)(rand() % 40); // 50-90 range
 data.motion_detected = (rand() % 2 == 0);
 data.timestamp = i * 1000;

 // Process through hybrid control
 ActuatorAction action = hybrid_control(&data, MODE_HYBRID);

 // Execute decision
 execute_action(action);
 }

 printf("\n=== Monitoring Complete ===\n");
}

/* Main entry point */
int main(void) {
 printf("========================================\n");
 printf(" IoT Control Flow - C Implementation\n");
 printf("========================================\n");

 // Initialize random seed
 srand(42);

 // Test Scenario 1: Edge Control Mode
 printf("\n[TEST 1] Edge-Based Control\n");
 SensorData test_data = {28.0f, 65.0f, false, 1000};
 ActuatorAction result = hybrid_control(&test_data, MODE_EDGE);
 execute_action(result);

 // Test Scenario 2: Cloud Control Mode
 printf("\n[TEST 2] Centralized (Cloud) Control\n");
 test_data.temperature = 32.0f;
 test_data.humidity = 75.0f;
 test_data.motion_detected = true;
 result = hybrid_control(&test_data, MODE_CENTRALIZED);
 execute_action(result);

 // Test Scenario 3: Hybrid with critical temperature
 printf("\n[TEST 3] Hybrid Control - Critical Temperature\n");
 test_data.temperature = 38.0f; // Above critical threshold
 result = hybrid_control(&test_data, MODE_HYBRID);
 execute_action(result);

 // Test Scenario 4: Continuous monitoring loop
 run_monitoring_loop(5);

 printf("\n========================================\n");
 printf(" Program Execution Complete\n");
 printf("========================================\n");

 return 0;
}
